function trySpendTwice(sender, addressA, addressB, amount) {
  // The mempool exhausts the small UTXO that backed the first send,
  // so the second send (same sender, same amount) ends up trying to
  // spend an UTXO that's already encumbered. The harness rejects.
  const { txid: [[SLOT dest_alias]] } = chain.send(sender, addressA, amount);
  let secondError = [[SLOT init_err]];
  // Drain the sender to one UTXO so the second send genuinely runs
  // out of inputs. We do this by sending the same large amount again
  // expecting the second send to fail because the UTXO is already in
  // the mempool / the sender's balance won't cover both.
  try {
    const huge = [[SLOT balance_fn]](sender.p2wpkhAddress);
    chain.send(sender, addressB, huge + amount);
  } catch (e) {
    secondError = [[SLOT error_extract]];
  }
  return { firstTxid, secondError };
}
